(function () {
  function loadScript() {
    function waitForDeps() {
      if (typeof jQuery === "undefined" || typeof ebix_Promotion === "undefined") {
        return setTimeout(waitForDeps, 100);
      }

      if (window.__MAIN_JS_LOADED__) return;
      window.__MAIN_JS_LOADED__ = true;

      var scripts = document.querySelectorAll('script[src*="app.min.js"]');
      if (!scripts.length) return;

      var current = scripts[scripts.length - 1];

      var script = document.createElement("script");
      script.src = current.src.replace("app.min.js", "main.js");

      document.head.appendChild(script);
    }

    waitForDeps();
  }

  if (document.readyState === "loading") {
    document.addEventListener("DOMContentLoaded", loadScript);
  } else {
    loadScript();
  }
})();